package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Writer;
import java.lang.reflect.Field;
import java.nio.charset.Charset;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

public class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testPrint_withValidPathAndCharset_returnsCSVPrinter() throws IOException, ReflectiveOperationException {
        Path mockPath = mock(Path.class);
        CSVPrinter mockPrinter = mock(CSVPrinter.class);

        // Create a Writer instance to be returned by Files.newBufferedWriter
        Writer writer = new java.io.StringWriter();

        // Use reflection to replace Files.newBufferedWriter call inside CSVFormat.print(Path, Charset)
        // Since Mockito.mockStatic is not available, we create a subclass of CSVFormat to override print(Path, Charset)
        CSVFormat spyFormat = spy(csvFormat);

        doReturn(mockPrinter).when(spyFormat).print(any(Appendable.class));

        // Override the print(Path, Charset) method via reflection or subclassing
        CSVFormat formatWithOverride = new CSVFormatOverride(spyFormat, writer);

        CSVPrinter printer = formatWithOverride.print(mockPath, StandardCharsets.UTF_8);

        assertNotNull(printer);
        assertSame(mockPrinter, printer);
    }

    @Test
    public void testPrint_throwsIOException_whenFilesNewBufferedWriterThrows() {
        Path mockPath = mock(Path.class);

        // Since we cannot mock static Files.newBufferedWriter, test by subclassing CSVFormat to throw IOException
        CSVFormat formatWithException = new CSVFormatThrowing();

        IOException thrown = assertThrows(IOException.class, () -> {
            formatWithException.print(mockPath, StandardCharsets.UTF_8);
        });

        assertEquals("Test IO Exception", thrown.getMessage());
    }

    // Helper subclass to override print(Path, Charset) method to avoid calling Files.newBufferedWriter
    static class CSVFormatOverride extends CSVFormat {
        private final CSVFormat delegate;
        private final Writer writer;

        CSVFormatOverride(CSVFormat delegate, Writer writer) {
            super(delegate.getDelimiter(),
                  delegate.getQuoteCharacter(),
                  delegate.getQuoteMode(),
                  delegate.getCommentMarker(),
                  delegate.getEscapeCharacter(),
                  delegate.getIgnoreSurroundingSpaces(),
                  delegate.getIgnoreEmptyLines(),
                  delegate.getRecordSeparator(),
                  delegate.getNullString(),
                  null,
                  delegate.getHeader(),
                  delegate.getSkipHeaderRecord(),
                  delegate.getAllowMissingColumnNames(),
                  delegate.getIgnoreHeaderCase(),
                  delegate.getTrim(),
                  delegate.getTrailingDelimiter(),
                  delegate.getAutoFlush());
            this.delegate = delegate;
            this.writer = writer;
        }

        @Override
        public CSVPrinter print(Path out, Charset charset) throws IOException {
            // Instead of calling Files.newBufferedWriter, return print(writer)
            return delegate.print(writer);
        }
    }

    // Helper subclass to override print(Path, Charset) method to throw IOException
    static class CSVFormatThrowing extends CSVFormat {
        CSVFormatThrowing() {
            super(CSVFormat.DEFAULT.getDelimiter(),
                  CSVFormat.DEFAULT.getQuoteCharacter(),
                  CSVFormat.DEFAULT.getQuoteMode(),
                  CSVFormat.DEFAULT.getCommentMarker(),
                  CSVFormat.DEFAULT.getEscapeCharacter(),
                  CSVFormat.DEFAULT.getIgnoreSurroundingSpaces(),
                  CSVFormat.DEFAULT.getIgnoreEmptyLines(),
                  CSVFormat.DEFAULT.getRecordSeparator(),
                  CSVFormat.DEFAULT.getNullString(),
                  null,
                  CSVFormat.DEFAULT.getHeader(),
                  CSVFormat.DEFAULT.getSkipHeaderRecord(),
                  CSVFormat.DEFAULT.getAllowMissingColumnNames(),
                  CSVFormat.DEFAULT.getIgnoreHeaderCase(),
                  CSVFormat.DEFAULT.getTrim(),
                  CSVFormat.DEFAULT.getTrailingDelimiter(),
                  CSVFormat.DEFAULT.getAutoFlush());
        }

        @Override
        public CSVPrinter print(Path out, Charset charset) throws IOException {
            throw new IOException("Test IO Exception");
        }
    }
}
